import{c as i,Q as r,j as t,m as o}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"OpenViking Memory Provider","description":"","frontmatter":{},"headers":[],"relativePath":"memory-providers/openviking.md","filePath":"memory-providers/openviking.md","lastUpdated":1774787421000}'),n={name:"memory-providers/openviking.md"};function a(d,e,s,g,l,p){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="openviking-memory-provider" tabindex="-1">OpenViking Memory Provider <a class="header-anchor" href="#openviking-memory-provider" aria-label="Permalink to &quot;OpenViking Memory Provider&quot;">​</a></h1><p>OpenViking is a memory provider that can be self-hosted or used as a SaaS service. It provides an alternative memory backend for bots that need a dedicated memory API.</p><hr><h2 id="creating-an-openviking-provider" tabindex="-1">Creating an OpenViking Provider <a class="header-anchor" href="#creating-an-openviking-provider" aria-label="Permalink to &quot;Creating an OpenViking Provider&quot;">​</a></h2><ol><li>Navigate to the <strong>Memory Providers</strong> page.</li><li>Click <strong>Add Memory Provider</strong>.</li><li>Fill in the following fields: <ul><li><strong>Name</strong>: A display name for this provider.</li><li><strong>Provider Type</strong>: Select <code>openviking</code>.</li></ul></li><li>Click <strong>Create</strong>.</li></ol><hr><h2 id="configuring-an-openviking-provider" tabindex="-1">Configuring an OpenViking Provider <a class="header-anchor" href="#configuring-an-openviking-provider" aria-label="Permalink to &quot;Configuring an OpenViking Provider&quot;">​</a></h2><p>After creating a provider, select it from the list and configure its settings.</p><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Base URL</strong></td><td>Yes</td><td>OpenViking API endpoint (e.g. <code>http://openviking:8088</code>).</td></tr><tr><td><strong>API Key</strong></td><td>No</td><td>API key for authentication (stored as a secret).</td></tr></tbody></table><hr><h2 id="assigning-an-openviking-provider-to-a-bot" tabindex="-1">Assigning an OpenViking Provider to a Bot <a class="header-anchor" href="#assigning-an-openviking-provider-to-a-bot" aria-label="Permalink to &quot;Assigning an OpenViking Provider to a Bot&quot;">​</a></h2><ol><li>Navigate to the <strong>Bots</strong> page and open your bot.</li><li>Go to the <strong>General</strong> tab.</li><li>Find the <strong>Memory Provider</strong> dropdown.</li><li>Select the OpenViking provider you created.</li><li>Click <strong>Save</strong>.</li></ol><hr><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>Once assigned, the bot will use OpenViking as its memory backend. Memory extraction, search, and management operations are routed through the OpenViking API.</p><p>For day-to-day memory operations, see <a href="/getting-started/memory.html">Bot Memory Management</a>.</p>',16)])])}const c=i(n,[["render",a]]);export{m as __pageData,c as default};
